package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;
import java.util.HashMap;
import java.util.Map;

import org.junit.jupiter.api.Test;

class CSVRecordTest {

    @Test
    void testIsConsistent_mappingNull() throws Exception {
        // Prepare CSVRecord instance with mapping == null
        String[] values = new String[] {"a", "b", "c"};
        Map<String, Integer> mapping = null;
        String comment = "comment";
        long recordNumber = 1L;

        CSVRecord record = createCSVRecord(values, mapping, comment, recordNumber);

        // Use reflection to invoke private constructor if needed or use factory method
        // Here constructor is package-private, so we can instantiate directly because test is in same package

        // Test isConsistent returns true if mapping is null
        boolean result = record.isConsistent();
        assertTrue(result);
    }

    @Test
    void testIsConsistent_mappingSizeEqualsValuesLength() throws Exception {
        // Prepare mapping with size equal to values.length
        String[] values = new String[] {"val1", "val2", "val3"};
        Map<String, Integer> mapping = new HashMap<>();
        mapping.put("col1", 0);
        mapping.put("col2", 1);
        mapping.put("col3", 2);
        String comment = null;
        long recordNumber = 10L;

        CSVRecord record = createCSVRecord(values, mapping, comment, recordNumber);

        boolean result = record.isConsistent();
        assertTrue(result);
    }

    @Test
    void testIsConsistent_mappingSizeNotEqualsValuesLength() throws Exception {
        // Prepare mapping with size not equal to values.length
        String[] values = new String[] {"val1", "val2"};
        Map<String, Integer> mapping = new HashMap<>();
        mapping.put("col1", 0);
        mapping.put("col2", 1);
        mapping.put("col3", 2);
        String comment = null;
        long recordNumber = 5L;

        CSVRecord record = createCSVRecord(values, mapping, comment, recordNumber);

        boolean result = record.isConsistent();
        assertFalse(result);
    }

    private CSVRecord createCSVRecord(String[] values, Map<String, Integer> mapping, String comment, long recordNumber) throws Exception {
        // The constructor is package-private, so we can instantiate directly here because test is in same package
        return new CSVRecord(values, mapping, comment, recordNumber);
    }
}
